+	// Should have used the explorer's system prompt.
+	if !strings.Contains(subagentSystemPrompt, "codebase exploration specialist") {
+		t.Errorf("subagent should use explorer prompt, got:\n%.200s...", subagentSystemPrompt)
+	}
